#include <bits/stdc++.h>
using namespace std;

int lucky_num[1002010];

void make_lucky_num(int a) {
    for (int i = 1; i <= 1001; i++) {
        int t = i * i;
        if (t >= a) {
            for (int j = t; j <= 1002001; j += t) {
                if (j >= a) {
                    lucky_num[j] = 1002005;
                }
            }
        }
    }
    int t = 1002001;
    for (int i = 1002001; i >= 0; i--) {
        if (lucky_num[i]) t = i;
        else lucky_num[i] = t;
    }
}

int main() {
    int a, n;
    cin >> a >> n;
    make_lucky_num(a);
    for (int i = 0; i < n; i++) {
        int x;
        cin >> x;
        if (lucky_num[x] == 1002005)
            printf("lucky\n");
        else {
            printf("%d\n", lucky_num[x]);
        }
    }
    return 0;
}
